# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory backend for coordinating users, projects, tasks,
messaging, performance metrics and reporting. The public surface is the
``TeamCollaborationManager`` class together with the supporting enums,
exception hierarchy and immutable-by-copy data records.

Standard library only. All mutating and reading operations are guarded by a
single shared re-entrant lock so the manager is safe to use from multiple
threads. Every getter returns a deep copy so callers can never mutate the
internal store by holding on to a returned object.
"""

import copy
import csv
import enum
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from typing import List, Optional


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class UserRole(enum.Enum):
    """Role a user holds within the system."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(enum.Enum):
    """Lifecycle status for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(enum.Enum):
    """Supported export formats for generated reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(enum.Enum):
    """Discriminator identifying the shape of a report payload."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Data records
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    description: str = ""
    assignee_id: Optional[int] = None
    status: TaskStatus = TaskStatus.NOT_STARTED
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime
    data: bytes = b""


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Internal store / component holders
# ---------------------------------------------------------------------------
class _Store:
    """A keyed collection of records that shares the manager's lock."""

    def __init__(self, lock):
        self._lock = lock
        self._items = {}


class _Component:
    """A logical service surface that shares the manager's lock."""

    def __init__(self, lock):
        self._lock = lock


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Coordinates users, projects, tasks, messaging and reporting."""

    def __init__(self, now=None):
        # Single re-entrant lock shared by every sub-store/component so that
        # composite operations remain atomic and deadlock-free.
        self._lock = threading.RLock()

        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Component(self._lock)
        self.reports = _Component(self._lock)

        self._ratings = {}
        self._counter = 0
        self._now = now if now is not None else datetime.now

    # -- internal helpers --------------------------------------------------
    def _next_id(self):
        self._counter += 1
        return self._counter

    @staticmethod
    def _clone(obj):
        return copy.deepcopy(obj)

    @staticmethod
    def _valid_email(email):
        if not isinstance(email, str):
            return False
        if not email.strip() or "@" not in email:
            return False
        local, _, domain = email.partition("@")
        return bool(local) and bool(domain)

    def _require_user(self, user_id):
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id):
        message = self.messages._items.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    def _username_taken(self, username, exclude_id=None):
        for user in self.users._items.values():
            if user.id != exclude_id and user.username == username:
                return True
        return False

    def _email_taken(self, email, exclude_id=None):
        for user in self.users._items.values():
            if user.id != exclude_id and user.email == email:
                return True
        return False

    def _user_tasks(self, user_id, project_id=None):
        return [
            task
            for task in self.tasks._items.values()
            if task.assignee_id == user_id
            and (project_id is None or task.project_id == project_id)
        ]

    # -- user management ---------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            if not isinstance(username, str) or not username.strip():
                raise ValidationError("username is required")
            if not self._valid_email(email):
                raise ValidationError("a valid email is required")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if self._username_taken(username):
                raise DuplicateError("username already in use")
            if self._email_taken(email):
                raise DuplicateError("email already in use")

            user_id = self._next_id()
            user = User(
                id=user_id,
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users._items[user_id] = user
            return self._clone(user)

    def get_user(self, user_id):
        with self._lock:
            return self._clone(self._require_user(user_id))

    def list_users(self):
        with self._lock:
            users = sorted(self.users._items.values(), key=lambda u: u.id)
            return [self._clone(u) for u in users]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self._require_user(user_id)

            if username is not None:
                if not isinstance(username, str) or not username.strip():
                    raise ValidationError("username is required")
                if self._username_taken(username, exclude_id=user_id):
                    raise DuplicateError("username already in use")
            if email is not None:
                if not self._valid_email(email):
                    raise ValidationError("a valid email is required")
                if self._email_taken(email, exclude_id=user_id):
                    raise DuplicateError("email already in use")
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None:
                user.username = username
            if email is not None:
                user.email = email
            if role is not None:
                user.role = role
            return self._clone(user)

    def delete_user(self, user_id):
        with self._lock:
            self._require_user(user_id)
            for project in self.projects._items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")
            for task in self.tasks._items.values():
                if (
                    task.assignee_id == user_id
                    and task.status != TaskStatus.COMPLETED
                ):
                    raise ConflictError("user has open tasks assigned")
            del self.users._items[user_id]

    # -- project management ------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            self._require_user(owner_id)
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name is required")
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")

            project_id = self._next_id()
            project = Project(
                id=project_id,
                name=name,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description or "",
            )
            self.projects._items[project_id] = project
            return self._clone(project)

    def get_project(self, project_id):
        with self._lock:
            return self._clone(self._require_project(project_id))

    def list_projects(self):
        with self._lock:
            projects = sorted(self.projects._items.values(), key=lambda p: p.id)
            return [self._clone(p) for p in projects]

    def update_project(
        self, project_id, name=None, start_date=None, end_date=None, description=None
    ):
        with self._lock:
            project = self._require_project(project_id)

            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date

            if name is not None and (not isinstance(name, str) or not name.strip()):
                raise ValidationError("project name is required")
            if new_end < new_start:
                raise ValidationError("end_date cannot precede start_date")

            if name is not None:
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return self._clone(project)

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)

            task_ids = [
                tid
                for tid, task in self.tasks._items.items()
                if task.project_id == project_id
            ]
            task_id_set = set(task_ids)
            for tid in task_ids:
                del self.tasks._items[tid]

            message_ids = [
                mid
                for mid, message in self.messages._items.items()
                if message.project_id == project_id
                or message.task_id in task_id_set
            ]
            for mid in message_ids:
                del self.messages._items[mid]

            del self.projects._items[project_id]

    # -- task management ---------------------------------------------------
    def create_task(
        self, project_id, title, assignee_id=None, deadline=None, description=""
    ):
        with self._lock:
            project = self._require_project(project_id)
            if assignee_id is not None:
                self._require_user(assignee_id)
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title is required")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")

            task_id = self._next_id()
            task = Task(
                id=task_id,
                project_id=project_id,
                title=title,
                description=description or "",
                assignee_id=assignee_id,
                status=TaskStatus.NOT_STARTED,
                deadline=deadline,
                created_at=self._now(),
            )
            self.tasks._items[task_id] = task
            return self._clone(task)

    def get_task(self, task_id):
        with self._lock:
            return self._clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tasks = sorted(
                (
                    task
                    for task in self.tasks._items.values()
                    if task.project_id == project_id
                ),
                key=lambda t: t.id,
            )
            return [self._clone(t) for t in tasks]

    def list_tasks_by_assignee(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = sorted(self._user_tasks(user_id), key=lambda t: t.id)
            return [self._clone(t) for t in tasks]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            task.assignee_id = assignee_id
            return self._clone(task)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            task.assignee_id = new_assignee_id
            return self._clone(task)

    def unassign_task(self, task_id):
        with self._lock:
            task = self._require_task(task_id)
            task.assignee_id = None
            return self._clone(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects._items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return self._clone(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None

            task.status = status
            return self._clone(task)

    # -- messaging ---------------------------------------------------------
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ):
        with self._lock:
            self._require_user(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            attachment_specs = list(attachments) if attachments else []
            has_body = isinstance(body, str) and bool(body.strip())
            if not has_body and not attachment_specs:
                raise ValidationError("message requires a body or an attachment")

            now = self._now()
            attachment_objs = [
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                    data=bytes(data),
                )
                for filename, data in attachment_specs
            ]

            message_id = self._next_id()
            message = Message(
                id=message_id,
                author_id=author_id,
                body=body if isinstance(body, str) else "",
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=now,
            )
            self.messages._items[message_id] = message
            return self._clone(message)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            if not isinstance(new_body, str) or not new_body.strip():
                raise ValidationError("message body is required")
            message.body = new_body
            message.edited_at = self._now()
            return self._clone(message)

    def add_attachment(self, message_id, user_id, filename, data):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError(
                    "only the author may attach to a message"
                )
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("filename is required")
            attachment = Attachment(
                filename=filename,
                size=len(data),
                uploaded_by=user_id,
                uploaded_at=self._now(),
                data=bytes(data),
            )
            message.attachments.append(attachment)
            return self._clone(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            messages = sorted(
                (
                    message
                    for message in self.messages._items.values()
                    if message.project_id == project_id
                ),
                key=lambda m: m.id,
            )
            return [self._clone(m) for m in messages]

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            messages = sorted(
                (
                    message
                    for message in self.messages._items.values()
                    if message.task_id == task_id
                ),
                key=lambda m: m.id,
            )
            return [self._clone(m) for m in messages]

    def delete_message(self, message_id, user_id):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may delete a message")
            del self.messages._items[message_id]

    # -- performance dashboard --------------------------------------------
    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._user_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            durations = self._completion_durations(self._user_tasks(user_id))
            if not durations:
                return None
            return sum(durations) / len(durations)

    @staticmethod
    def _completion_durations(tasks):
        durations = []
        for task in tasks:
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append(
                    (task.completed_at - task.started_at).total_seconds()
                )
        return durations

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if (
                not isinstance(score, int)
                or isinstance(score, bool)
                or not (1 <= score <= 5)
            ):
                raise ValidationError("score must be an integer between 1 and 5")
            if task_id is not None:
                self._require_task(task_id)

            rating_id = self._next_id()
            rating = Rating(
                id=rating_id,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self._ratings[rating_id] = rating
            return self._clone(rating)

    def _ratings_for(self, user_id):
        ratings = [
            rating
            for rating in self._ratings.values()
            if rating.ratee_id == user_id
        ]
        ratings.sort(key=lambda r: r.id)
        return ratings

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for(user_id)
            if not ratings:
                return {"count": 0, "average": 0.0, "ratings": []}
            average = sum(r.score for r in ratings) / len(ratings)
            return {
                "count": len(ratings),
                "average": average,
                "ratings": [self._clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._user_tasks(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            durations = self._completion_durations(tasks)
            average_time = (
                sum(durations) / len(durations) if durations else None
            )
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": average_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # -- reports -----------------------------------------------------------
    def project_progress_report(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tasks = [
                task
                for task in self.tasks._items.values()
                if task.project_id == project_id
            ]
            total = len(tasks)
            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]

            now = self._now()
            overdue = sum(
                1
                for task in tasks
                if task.deadline is not None
                and task.deadline < now
                and task.status != TaskStatus.COMPLETED
            )

            per_assignee = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id, {"total": 0, "completed": 0}
                )
                bucket["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
                "generated_at": now,
            }

    def _performance_row(self, user_id, project_id=None):
        user = self.users._items.get(user_id)
        tasks = self._user_tasks(user_id, project_id)
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        durations = self._completion_durations(tasks)
        average_time = sum(durations) / len(durations) if durations else None
        ratings = self._ratings_for(user_id)
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count if rating_count else 0.0
        )
        return {
            "user_id": user_id,
            "username": user.username if user is not None else None,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": (completed / total) if total else 0.0,
            "average_completion_time": average_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
            tasks = [
                task
                for task in self.tasks._items.values()
                if project_id is None or task.project_id == project_id
            ]
            user_ids = sorted(
                {
                    task.assignee_id
                    for task in tasks
                    if task.assignee_id is not None
                }
            )
            rows = [
                self._performance_row(user_id, project_id)
                for user_id in user_ids
            ]
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "generated_at": self._now(),
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = sorted(self._user_tasks(user_id), key=lambda t: t.id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            durations = self._completion_durations(tasks)
            average_time = (
                sum(durations) / len(durations) if durations else None
            )
            task_rows = [
                {
                    "task_id": task.id,
                    "title": task.title,
                    "status": task.status.value,
                    "project_id": task.project_id,
                    "assignee_id": task.assignee_id,
                    "deadline": task.deadline,
                    "started_at": task.started_at,
                    "completed_at": task.completed_at,
                }
                for task in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": average_time,
                "tasks": task_rows,
            }

    def export_report(self, report, fmt):
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dict")
        if fmt == ReportFormat.CSV:
            return self._report_to_csv(report)
        return self._report_to_pdf(report)

    # -- export helpers ----------------------------------------------------
    @staticmethod
    def _csv_cell(value):
        if value is None:
            return ""
        return value

    def _report_to_csv(self, report):
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        report_type = report.get("report_type")

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            columns = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            writer.writerow(columns)
            for row in report.get("rows", []):
                writer.writerow([self._csv_cell(row.get(c)) for c in columns])
        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            writer.writerow(
                [
                    "user_id",
                    "total_tasks",
                    "completed_tasks",
                    "completion_rate",
                    "average_completion_time",
                ]
            )
            writer.writerow(
                [
                    self._csv_cell(report.get("user_id")),
                    self._csv_cell(report.get("total_tasks")),
                    self._csv_cell(report.get("completed_tasks")),
                    self._csv_cell(report.get("completion_rate")),
                    self._csv_cell(report.get("average_completion_time")),
                ]
            )
            writer.writerow([])
            task_columns = [
                "task_id",
                "title",
                "status",
                "project_id",
                "assignee_id",
                "deadline",
                "started_at",
                "completed_at",
            ]
            writer.writerow(task_columns)
            for task in report.get("tasks", []):
                writer.writerow(
                    [self._csv_cell(task.get(c)) for c in task_columns]
                )
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, self._csv_cell(value)])

        return buffer.getvalue()

    def _report_to_pdf(self, report):
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            lines.append("{0}: {1}".format(key, value))
        return self._build_pdf(lines)

    @staticmethod
    def _pdf_escape(text):
        text = str(text)
        text = (
            text.replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
            .replace("\r", " ")
            .replace("\n", " ")
        )
        return text.encode("ascii", "replace")

    def _pdf_content_stream(self, lines):
        parts = [b"BT", b"/F1 12 Tf", b"72 720 Td", b"14 TL"]
        first = True
        for line in lines:
            escaped = self._pdf_escape(line)
            if first:
                parts.append(b"(" + escaped + b") Tj")
                first = False
            else:
                parts.append(b"T* (" + escaped + b") Tj")
        parts.append(b"ET")
        return b"\n".join(parts)

    def _build_pdf(self, lines):
        content = self._pdf_content_stream(lines)
        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (
                b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
                b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
            ),
            (
                b"<< /Length "
                + str(len(content)).encode("ascii")
                + b" >>\nstream\n"
                + content
                + b"\nendstream"
            ),
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        out = bytearray(b"%PDF-1.4\n")
        offsets = []
        for index, body in enumerate(objects, start=1):
            offsets.append(len(out))
            out += str(index).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

        xref_position = len(out)
        size = len(objects) + 1
        out += b"xref\n"
        out += b"0 " + str(size).encode("ascii") + b"\n"
        out += b"0000000000 65535 f \n"
        for offset in offsets:
            out += ("%010d 00000 n \n" % offset).encode("ascii")
        out += b"trailer\n"
        out += b"<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
        out += b"startxref\n"
        out += str(xref_position).encode("ascii") + b"\n"
        out += b"%%EOF\n"
        return bytes(out)
